lines = []
for pt, en in additions:
    lines.append(f'out = out.replace(\n    {repr(pt)},\n    {repr(en)},\n    1\n)\n')

with open('gen_en_pentateuco.py', 'a', encoding='utf-8') as f:
    f.write('\n# ═══ genesis section ═══\n')
    f.writelines(lines)

